// // This module implements an 8-bit binary counter that decrements on every positive clock edge if enabled and resets to 0 when reset is active.
module binary_counter_8bit(
    input           clk,
    input           rst,
    input           en,
    output reg [7:0] count
);

    always @(posedge clk or posedge rst) begin
        if (rst)
            count <= 8'b0;
        else if (en)
            count <= count + 1;
    end

endmodule
